def is_isomorphic(s, t):
    st, ts = {}, {}
    for a, b in zip(s, t):
        if a in st and st[a] != b:
            return False
        if b in ts and ts[b] != a:
            return False
        st[a] = b
        ts[b] = a
    return True

code.javascript:
function isIsomorphic(s, t) {
  const st = {};
  const ts = {};
  for (let i = 0; i < s.length; i++) {
    const a = s[i];
    const b = t[i];
    if (st[a] !== undefined && st[a] !== b) {
      return false;
    }
    if (ts[b] !== undefined && ts[b] !== a) {
      return false;
    }
    st[a] = b;
    ts[b] = a;
  }
  return true;
}

code.typescript:
function isIsomorphic(s: string, t: string): boolean {
  const st: Record<string, string> = {};
  const ts: Record<string, string> = {};
  for (let i = 0; i < s.length; i++) {
    const a = s[i];
    const b = t[i];
    if (st[a] !== undefined && st[a] !== b) {
      return false;
    }
    if (ts[b] !== undefined && ts[b] !== a) {
      return false;
    }
    st[a] = b;
    ts[b] = a;
  }
  return true;
}
